  `exam_start_time` datetime NOT NULL COMMENT '考试开始时间',
  `grading_data` json NOT NULL COMMENT '判卷结果数据，包含所有题目的分数和判分状态',
  `total_score` decimal(5,2) DEFAULT '0.00' COMMENT '总分',
